  function createSuccessOrderAnimation(totalText = "") {
    ensureSuccessOrderAnimationStyles();
    const shell = document.createElement("div");
    shell.className = "success-order-animation";
    shell.innerHTML = `
      <div class="soa-container">
        <div class="soa-left-side">
          <div class="soa-card">
            <div class="soa-card-line"></div>
            <div class="soa-buttons"></div>
          </div>
          <div class="soa-post">
            <div class="soa-post-line"></div>
            <div class="soa-screen">
              <div class="soa-dollar"></div>
            </div>
            <div class="soa-numbers"></div>
            <div class="soa-numbers-line2"></div>
          </div>
        </div>
        <div class="soa-right-side">
          <div class="soa-new">New Transaction</div>
          <svg viewBox="0 0 451.846 451.847" xmlns="http://www.w3.org/2000/svg" class="soa-arrow" aria-hidden="true" focusable="false">
            <path d="M345.441 248.292L151.154 442.573c-12.359 12.365-32.397 12.365-44.75 0-12.354-12.354-12.354-32.391 0-44.744L278.318 225.92 106.409 54.017c-12.354-12.359-12.354-32.394 0-44.748 12.354-12.359 32.391-12.359 44.75 0l194.287 194.284c6.177 6.18 9.262 14.271 9.262 22.366 0 8.099-3.091 16.196-9.267 22.373z"></path>
          </svg>
        </div>
      </div>
    `;
    const container = shell.querySelector(".soa-container");
    const screenNode = shell.querySelector(".soa-screen");
    const amountNode = shell.querySelector(".soa-dollar");
    const displayText = String(totalText || "$").trim() || "$";
    amountNode.textContent = displayText;
    const fitAmountNode = () => {
      if (!amountNode) return;
      amountNode.style.fontSize = "15px";
      amountNode.style.letterSpacing = "0";
      const rawWidth = Number(screenNode?.clientWidth || amountNode.clientWidth || 0);
      const availableWidth = Math.floor(rawWidth - 4);
      if (!Number.isFinite(availableWidth) || availableWidth < 30) return;
      let size = 15;
      while (size > 11 && amountNode.scrollWidth > availableWidth) {
        size -= 0.5;
        amountNode.style.fontSize = `${size}px`;
      }
      if (amountNode.scrollWidth > availableWidth) {
        amountNode.style.letterSpacing = "-0.2px";
        while (size > 10 && amountNode.scrollWidth > availableWidth) {
          size -= 0.25;
          amountNode.style.fontSize = `${size}px`;
        }
      }
    };
    shell.__play = () => {
      try { if (shell.__playTimer) clearTimeout(shell.__playTimer); } catch (_) {}
      try { if (shell.__playStartTimer) clearTimeout(shell.__playStartTimer); } catch (_) {}
      if (container) {
        container.classList.remove("play");
        void container.offsetWidth;
      }
      shell.__playStartTimer = setTimeout(() => {
        fitAmountNode();
        requestAnimationFrame(() => {
          if (container) container.classList.add("play");
          requestAnimationFrame(fitAmountNode);
        });
      }, 120);
    };
    shell.__stop = () => {
      try { if (shell.__playTimer) clearTimeout(shell.__playTimer); } catch (_) {}
      try { if (shell.__playStartTimer) clearTimeout(shell.__playStartTimer); } catch (_) {}
      if (container) container.classList.remove("play");
    };
    return shell;
  }

