      var notFoundRoute = (function(){
        var state = { root: null, initialized: false };

        function ensureRoot(){
          if (state.root) return state.root;
          var tpl = document.getElementById('not-found-inline-template');
          var root = document.createElement('div');
          root.id = 'notFoundInlineHost';
          if (tpl && tpl.content) {
            root.appendChild(tpl.content.cloneNode(true));
          }
          state.root = root;
          return root;
        }

        function build(){
          return ensureRoot();
        }

        function bindButton(selector, handler){
          var root = ensureRoot();
          var btn = root.querySelector(selector);
          if (!btn || btn.dataset.bound === '1') return;
          btn.dataset.bound = '1';
          btn.addEventListener('click', function(event){
            try { event.preventDefault(); } catch(_){ }
            try { handler(); } catch(_){ }
          });
        }

        function init(){
          if (state.initialized) return true;
          var root = ensureRoot();
          if (!root.querySelector('#notFoundInline')) return false;
          bindButton('[data-not-found-home]', function(){
            if (typeof window.navigateHome === 'function') {
              window.navigateHome();
              return;
            }
            try { location.hash = '#/'; } catch(_){ }
          });
          bindButton('[data-not-found-login]', function(){
            if (typeof navigate === 'function') {
              navigate('login');
              return;
            }
            try { location.hash = '#/login'; } catch(_){ }
          });
          state.initialized = true;
          return true;
        }

        function resolveAttemptedPath(ctx){
          var attempted = '';
          try {
            var parts = (ctx && Array.isArray(ctx.routeParts)) ? ctx.routeParts.slice() : [];
            if (parts.length) attempted = '/' + parts.join('/');
            else if (ctx && ctx.routeValue) attempted = '/' + String(ctx.routeValue || '').replace(/^\/+/, '');
          } catch(_){ attempted = ''; }
          if (!attempted) {
            try {
              attempted = String(location.pathname || '').trim();
              if (!attempted || attempted === '/' || /\/index\.html$/i.test(attempted)) attempted = '';
            } catch(_){ attempted = ''; }
          }
          try {
            var search = String(location.search || '').trim();
            if (attempted && search) attempted += search;
          } catch(_){ }
          return attempted;
        }

        function onShow(ctx){
          init();
          var root = ensureRoot();
          var wrap = root.querySelector('[data-not-found-path]');
          var pathNode = root.querySelector('[data-not-found-path-text]');
          var attemptedPath = resolveAttemptedPath(ctx || {});
          if (wrap) wrap.hidden = !attemptedPath;
          if (pathNode) pathNode.textContent = attemptedPath || '/';
          try {
            if (window.__I18N__ && typeof window.__I18N__.applyTranslations === 'function') {
              window.__I18N__.applyTranslations(root);
            }
          } catch(_){ }
        }

        return {
          build: build,
          onShow: onShow,
          ready: function(){ return true; }
        };
      })();

